CREATE OR REPLACE FUNCTION f_get_chq_no ( as_vourcher_no text ,as_shot_app text) RETURNS varchar AS $body$
DECLARE

    ls_chq_no varchar(10);
    ls_ref_docno varchar(50);
    ls_ref_system varchar(10);

BEGIN
--  if trim(as_shot_app) = 'DEP' then
    select sc_fin_vourcher_detail.ref_system
    ,sc_fin_vourcher_detail.ref_docno
    into STRICT ls_ref_system , ls_ref_docno
    from sc_fin_vourcher_detail
    where vourcher_no = as_vourcher_no

    group by sc_fin_vourcher_detail.ref_system
    ,sc_fin_vourcher_detail.ref_docno;

      if ls_ref_system in ('TRS','TLS') then
          select fin_bank into STRICT ls_chq_no
          from sc_com_m_receipt
          where receipt_no = ls_ref_docno;
      else
          ls_chq_no := '';
      end if;
--    if  ls_ref_system in ('DDS','DCS','DOS','DWS') then
      if trim(both as_shot_app) = 'DEP' then
        select sc_dep_t_deposit_slip_item.chq_no
        into STRICT ls_chq_no
        from  sc_dep_t_deposit_slip
        ,     sc_dep_t_deposit_slip_item
        where sc_dep_t_deposit_slip.deposit_slip_no = sc_dep_t_deposit_slip_item.deposit_slip_no
        and   sc_dep_t_deposit_slip.deposit_slip_no = ls_ref_docno;
    else
        ls_chq_no := '';
    end if;

--  end if;
  RETURN ls_chq_no;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
